      endpoint: `https://api.zero.xyz/v1/proxy/${failed.id}`,
      authMode: "zeroxyz",
      pollIntervalMs: failed.pollIntervalMs,
      fieldMapping: { ...failed.fieldMapping },
      priority: 0, // set by caller
      enabled: true,
    };
  }
}

